CREATE TABLE IF NOT EXISTS public.filters (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, name text NOT NULL, query text NOT NULL, color text NOT NULL DEFAULT 'hsl(220, 10%, 50%)', position integer NOT NULL DEFAULT 0, is_favorite boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.filters ENABLE ROW LEVEL SECURITY; CREATE POLICY view_own_filters ON public.filters FOR SELECT USING (auth.uid() = user_id); CREATE POLICY insert_own_filters ON public.filters FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY update_own_filters ON public.filters FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY delete_own_filters ON public.filters FOR DELETE USING (auth.uid() = user_id); CREATE TRIGGER update_filters_updated_at BEFORE UPDATE ON public.filters FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column(); CREATE TABLE IF NOT EXISTS public.activity_log (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, entity_type text NOT NULL, entity_id uuid NOT NULL, action text NOT NULL, payload jsonb, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.activity_log ENABLE ROW LEVEL SECURITY; CREATE POLICY view_own_activity ON public.activity_log FOR SELECT USING (auth.uid() = user_id); CREATE POLICY insert_own_activity ON public.activity_log FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE INDEX IF NOT EXISTS idx_activity_log_user_created ON public.activity_log(user_id, created_at DESC); CREATE INDEX IF NOT EXISTS idx_tasks_user_due_date ON public.tasks(user_id, due_date); CREATE INDEX IF NOT EXISTS idx_tasks_user_project_position ON public.tasks(user_id, project_id, position); CREATE INDEX IF NOT EXISTS idx_tasks_user_completed_at ON public.tasks(user_id, completed_at); CREATE INDEX IF NOT EXISTS idx_tasks_parent_id ON public.tasks(parent_id); CREATE INDEX IF NOT EXISTS idx_tasks_due_datetime ON public.tasks(due_datetime); CREATE INDEX IF NOT EXISTS idx_projects_parent_id ON public.projects(parent_id);